  <fig-group>
    <fig-field>
      <label>Direction</label>
      <fig-dropdown full>
        <option selected>Horizontal</option>
        <option>Vertical</option>
      </fig-dropdown>
    </fig-field>
    <fig-field>
      <label>Spacing</label>
      <fig-slider value="8" min="0" max="64" text="true"></fig-slider>
    </fig-field>
  </fig-group>
